SELECT metric_id AS metricId, metric_type AS metricType, metric_name AS metricName, metric_value AS metricValue, metric_unit AS metricUnit, status, threshold, record_time AS recordTime, create_time AS createTime FROM sys_monitor_metrics
AND metric_type = #{req.metricType}
AND status = #{req.status}
ORDER BY record_time DESC
